from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import os
import pickle
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
from sklearn.pipeline import make_pipeline
from sklearn.preprocessing import StandardScaler

app = Flask(__name__)

# Load and encode employee images
def load_and_encode_images(image_dir):
    encodings = []
    labels = []
    for filename in os.listdir(image_dir):
        if filename.endswith('.jpg') or filename.endswith('.png'):
            image_path = os.path.join(image_dir, filename)
            image = face_recognition.load_image_file(image_path)
            encoding = face_recognition.face_encodings(image)
            if encoding:
                encodings.append(encoding[0])
                labels.append(filename.split('.')[0])
    return encodings, labels

# Train the model
def train_model(encodings, labels):
    le = LabelEncoder()
    labels_encoded = le.fit_transform(labels)
    clf = make_pipeline(StandardScaler(), SVC(probability=True, kernel='linear'))
    clf.fit(encodings, labels_encoded)
    return clf, le

# Load images and train model
encodings, labels = load_and_encode_images('employee_photos')
model, label_encoder = train_model(encodings, labels)

# API endpoint for facial recognition
@app.route('/recognize', methods=['POST'])
def recognize():
    file = request.files['image']
    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)
    
    if not face_encodings:
        return jsonify({'error': 'No face detected'}), 400
    
    face_encoding = face_encodings[0]
    probabilities = model.predict_proba([face_encoding])[0]
    class_indices = np.argsort(probabilities)[::-1]
    response = {
        'predictions': [
            {'label': label_encoder.inverse_transform([i])[0], 'confidence': probabilities[i]}
            for i in class_indices
        ]
    }
    return jsonify(response)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)